// ─── Animated Counter ────────────────────────────────────────────────────────
function Counter({ target, suffix = "" }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        let start = 0;
        const step = target / 60;
        const timer = setInterval(() => {
          start += step;
          if (start >= target) { setCount(target); clearInterval(timer); }
          else setCount(Math.floor(start));
        }, 20);
        obs.disconnect();
      }
    });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [target]);
  return <span ref={ref}>{count}{suffix}</span>;
}

// ─── Feature Card ────────────────────────────────────────────────────────────
function FeatureCard({ icon, title, desc }) {
  return (
    <div
      style={{
        background: "white", borderRadius: 24, padding: 32,
        border: "1px solid rgba(44,138,78,0.12)",
        boxShadow: "0 4px 20px rgba(26,92,46,0.06)",
        transition: "all 0.4s", cursor: "default",
      }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = "translateY(-6px)";
        e.currentTarget.style.boxShadow = "0 20px 48px rgba(26,92,46,0.14)";
        e.currentTarget.style.borderColor = "rgba(44,138,78,0.3)";
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.boxShadow = "0 4px 20px rgba(26,92,46,0.06)";
        e.currentTarget.style.borderColor = "rgba(44,138,78,0.12)";
      }}
    >
      <div style={{ width: 56, height: 56, borderRadius: 16, background: "#e8f5ed", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, marginBottom: 20 }}>
        {icon}
      </div>
      <div style={{ fontSize: 20, fontWeight: 700, color: "#0f2d1a", marginBottom: 10 }}>{title}</div>
      <div style={{ fontSize: 15, color: "#5a8a6a", lineHeight: 1.7 }}>{desc}</div>
    </div>
  );
}

// ─── Navbar ──────────────────────────────────────────────────────────────────
function Navbar({ nav }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  return (
    <nav style={{
      position: "fixed", top: 0, width: "100%", zIndex: 100,
      padding: "16px 40px",
      display: "flex", alignItems: "center", justifyContent: "space-between",
      background: scrolled ? "rgba(255,255,255,0.95)" : "rgba(255,255,255,0.92)",
      backdropFilter: "blur(16px)",
      borderBottom: "1px solid rgba(44,138,78,0.12)",
      boxShadow: scrolled ? "0 4px 24px rgba(26,92,46,0.1)" : "0 2px 20px rgba(26,92,46,0.07)",
      transition: "all 0.3s", boxSizing: "border-box",
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ width: 42, height: 42, borderRadius: 12, background: "linear-gradient(135deg,#2d8a4e,#1a5c2e)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, boxShadow: "0 4px 14px rgba(44,138,78,0.35)" }}>🌿</div>
        <div>
          <div style={{ fontFamily: "'Playfair Display',serif", fontWeight: 700, fontSize: 18, color: "#1a5c2e" }}>CinnaPredict</div>
          <div style={{ fontSize: 10, color: "#5a8a6a", letterSpacing: "0.15em", textTransform: "uppercase" }}>Research System</div>
        </div>
      </div>
      <div style={{ display: "flex", gap: 32 }}>
        {[["#features","Features"],["#about","About"],["#research","Research"]].map(([href, label]) => (
          <a key={href} href={href} style={{ fontSize: 14, fontWeight: 500, color: "#2a5c3a", textDecoration: "none" }}>{label}</a>
        ))}
      </div>
      <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
        <button onClick={() => nav("/login")} style={{ fontSize: 14, fontWeight: 600, color: "#1a5c2e", background: "none", border: "none", cursor: "pointer", padding: "8px 16px", borderRadius: 99 }}>Sign In</button>
        <button onClick={() => nav("/signup")} style={{ fontSize: 14, fontWeight: 700, color: "white", background: "linear-gradient(135deg,#2d8a4e,#1a5c2e)", border: "none", padding: "10px 24px", borderRadius: 99, cursor: "pointer", boxShadow: "0 4px 16px rgba(44,138,78,0.4)" }}>Get Started</button>
      </div>
    </nav>
  );
}

